namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // ── CalculateTotal: DataRow (compile-time constants) ────────────────
    // DataRow doesn't support decimal literals, so we pass doubles and cast.

    [TestMethod]
    [DataRow(10.00, 1, 0.0,  10.00,  DisplayName = "Single item, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00,  DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62,  DisplayName = "Multiple items, 8% tax")]
    [DataRow(0.00,  5, 0.10, 0.00,   DisplayName = "Zero price yields zero total")]
    [DataRow(99.99, 0, 0.05, 0.00,   DisplayName = "Zero quantity yields zero total")]
    [DataRow(10.00, 1, 0.0,  10.00,  DisplayName = "Tax rate at lower bound (0%)")]
    [DataRow(10.00, 1, 1.0,  20.00,  DisplayName = "Tax rate at upper bound (100%)")]
    public void CalculateTotal_WithValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // ── CalculateTotal: DynamicData for richer scenarios ────────────────
    // DynamicData supports decimal directly and allows descriptive tuple names.

    public static IEnumerable<object[]> LargeOrderCases
    {
        get
        {
            yield return [1_000.00m, 100, 0.07m, 107_000.00m, "Bulk order with 7% tax"];
            yield return [0.01m, 1, 0.0m, 0.01m, "Minimum non-zero price"];
            yield return [49.99m, 2, 0.20m, 119.976m, "Two items with 20% tax"];
        }
    }

    [TestMethod]
    [DynamicData(nameof(LargeOrderCases))]
    public void CalculateTotal_LargeAndEdgeCases_ReturnsExpected(
        decimal unitPrice, int quantity, decimal taxRate, decimal expected, string scenario)
    {
        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expected, result, $"Failed for: {scenario}");
    }

    // ── CalculateTotal: invalid inputs ──────────────────────────────────

    [TestMethod]
    [DataRow(-1.0, 1,  0.10, "unitPrice",  DisplayName = "Negative unit price throws")]
    [DataRow(10.0, -1, 0.10, "quantity",    DisplayName = "Negative quantity throws")]
    [DataRow(10.0, 1,  -0.1, "taxRate",     DisplayName = "Negative tax rate throws")]
    [DataRow(10.0, 1,  1.01, "taxRate",     DisplayName = "Tax rate above 1 throws")]
    public void CalculateTotal_WithInvalidInputs_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate, string expectedParamName)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));

        Assert.AreEqual(expectedParamName, ex.ParamName);
    }

    // ── ApplyDiscount: DataRow ──────────────────────────────────────────

    [TestMethod]
    [DataRow(100.00, 0.0,   100.00, DisplayName = "0% discount returns original")]
    [DataRow(100.00, 100.0, 0.00,   DisplayName = "100% discount returns zero")]
    [DataRow(200.00, 25.0,  150.00, DisplayName = "25% off 200")]
    [DataRow(49.99,  10.0,  44.991, DisplayName = "10% off 49.99")]
    [DataRow(0.00,   50.0,  0.00,   DisplayName = "Discount on zero price")]
    public void ApplyDiscount_WithValidInputs_ReturnsExpected(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // ── ApplyDiscount: DynamicData with method source ───────────────────

    public static IEnumerable<object[]> GetDiscountEdgeCases()
    {
        yield return [999_999.99m, 50.0m, 499_999.995m, "Large price with 50% discount"];
        yield return [0.01m, 99.0m, 0.0001m, "Near-total discount on tiny price"];
        yield return [100.0m, 33.33m, 66.67m, "Repeating decimal discount"];
    }

    [TestMethod]
    [DynamicData(nameof(GetDiscountEdgeCases), DynamicDataSourceType.Method)]
    public void ApplyDiscount_EdgeCases_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected, string scenario)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result, $"Failed for: {scenario}");
    }

    // ── ApplyDiscount: invalid inputs ───────────────────────────────────

    [TestMethod]
    [DataRow(100.0, -1.0,  DisplayName = "Negative discount throws")]
    [DataRow(100.0, 100.1, DisplayName = "Discount over 100% throws")]
    public void ApplyDiscount_WithInvalidDiscount_ThrowsArgumentOutOfRange(
        double price, double discountPercent)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent));

        Assert.AreEqual("discountPercent", ex.ParamName);
    }
}

